import { Component, OnInit } from '@angular/core';
import { Router, ActivatedRoute } from '@angular/router';
import { first } from 'rxjs/operators';

import { AccountService, AlertService } from '@app/_services';

enum EmailStatus {
    Verifying,
    Failed
}

@Component({
    templateUrl: 'verify-email.component.html',
    standalone: false
})
export class VerifyEmailComponent implements OnInit {
    EmailStatus = EmailStatus;
    emailStatus = EmailStatus.Verifying;

    constructor(
        private route: ActivatedRoute,
        private router: Router,
        private accountService: AccountService,
        private alertService: AlertService
    ) {}

    ngOnInit() {
        const token = this.route.snapshot.queryParams['token'];

        // remove token from url to prevent http referer leakage
        this.router.navigate([], { relativeTo: this.route, replaceUrl: true });

        this.accountService.verifyEmail(token)
            .pipe(first())
            .subscribe({
                next: () => {
                    this.alertService.success('Verification successful, you can now login', { keepAfterRouteChange: true });
                    this.router.navigate(['../login'], { relativeTo: this.route });
                },
                error: () => {
                    this.emailStatus = EmailStatus.Failed;
                }
            });
    }
}
<div class="auth-header">
    <h2 class="auth-title">Account Verification</h2>
    <p class="auth-subtitle">Confirming your email registration</p>
</div>
<div class="auth-body text-center">
    <div *ngIf="emailStatus === EmailStatus.Verifying" class="p-3">
        <span class="spinner-border spinner-border-lg text-primary mb-3"></span>
        <div class="text-secondary fw-semibold">Verifying your token details...</div>
    </div>
    <div *ngIf="emailStatus === EmailStatus.Failed" class="p-3">
        <div class="text-danger mb-3" style="font-size: 2.5rem;"><i class="bi bi-x-circle-fill"></i></div>
        <div class="text-white fw-bold mb-2">Verification Failed</div>
        <p class="text-secondary small mb-4">The verification token is invalid or has expired.</p>
        <a routerLink="/account/forgot-password" class="btn btn-outline-light w-100">Request New Code</a>
    </div>
</div>
